"use client";
import { useRouter } from "next/navigation";
import { useState, useRef, useEffect } from "react";
import { SearchFilters as ISearchFilters } from "../types";
import { SPECIALIZATIONS, HOSPITALS } from "../data/mockData";
import { formatDate } from "../lib/utils";
import Calendar from "../components/ui/Calendar";

export default function ChannelPage() {
  const router = useRouter();
  const [filters, setFilters] = useState<ISearchFilters>({
    specialization: "", hospital: "", date: "", doctorName: "",
  });
  const [showCal, setShowCal] = useState(false);
  const calRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (calRef.current && !calRef.current.contains(e.target as Node)) {
        setShowCal(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const set = (key: keyof ISearchFilters, value: string) =>
    setFilters(f => ({ ...f, [key]: value }));

  const handleSearch = () => {
    const params = new URLSearchParams();
    if (filters.specialization) params.set("spec", filters.specialization);
    if (filters.hospital)       params.set("hospital", filters.hospital);
    if (filters.date)           params.set("date", filters.date);
    if (filters.doctorName)     params.set("name", filters.doctorName);
    router.push(`/channel/results?${params.toString()}`);
  };

  const selectStyle: React.CSSProperties = {
    width: "100%",
    background: "rgba(6,13,26,0.9)",
    border: "1px solid rgba(148,163,184,0.1)",
    borderRadius: 10,
    padding: "11px 14px",
    color: "#f1f5f9",
    fontSize: 14,
    fontFamily: "DM Sans, sans-serif",
    outline: "none",
    appearance: "none" as const,
    cursor: "pointer",
    transition: "border-color 0.2s",
  };

  const labelStyle: React.CSSProperties = {
    fontSize: 11, fontWeight: 600, color: "#475569",
    letterSpacing: 1.2, textTransform: "uppercase" as const,
    marginBottom: 7, display: "block",
  };

  return (
    <div style={{
      minHeight: "90vh",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      padding: "40px 24px",
    }}>

      {/* Header */}
      <div className="animate-fade-up" style={{ textAlign: "center", marginBottom: 40 }}>
        <div style={{
          display: "inline-flex", alignItems: "center", gap: 8,
          padding: "5px 14px", borderRadius: 99,
          border: "1px solid rgba(74,222,128,0.2)",
          background: "rgba(74,222,128,0.05)",
          marginBottom: 18, fontSize: 12, fontWeight: 500,
          color: "#4ade80", letterSpacing: 0.5,
        }}>
          <span style={{
            width: 5, height: 5, borderRadius: "50%",
            background: "#4ade80", display: "inline-block",
          }} />
          Live availability · 6 doctors online today
        </div>
        <h1 style={{
          fontFamily: "Syne, sans-serif", fontWeight: 800,
          fontSize: "clamp(1.8rem, 4vw, 2.8rem)",
          color: "#f1f5f9", letterSpacing: -1, marginBottom: 10,
        }}>
          Find the Right Doctor
        </h1>
        <p style={{ color: "#475569", fontSize: 15, maxWidth: 380, margin: "0 auto" }}>
          Search by specialization, hospital or name and book instantly.
        </p>
      </div>

      {/* Search card */}
      <div className="glass animate-fade-up-1" style={{
        width: "100%", maxWidth: 520, padding: "32px 28px",
      }}>

        {/* Specialization */}
        <div style={{ marginBottom: 18 }}>
          <label style={labelStyle}>Specialization</label>
          <div style={{ position: "relative" }}>
            <select
              value={filters.specialization}
              onChange={e => set("specialization", e.target.value)}
              style={selectStyle}
              onFocus={e => e.target.style.borderColor = "rgba(14,165,233,0.4)"}
              onBlur={e => e.target.style.borderColor = "rgba(148,163,184,0.1)"}
            >
              <option value="">All Specializations</option>
              {SPECIALIZATIONS.map(s => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
            <span style={{
              position: "absolute", right: 14, top: "50%",
              transform: "translateY(-50%)", color: "#475569",
              fontSize: 10, pointerEvents: "none",
            }}>▼</span>
          </div>
        </div>

        {/* Hospital */}
        <div style={{ marginBottom: 18 }}>
          <label style={labelStyle}>Hospital</label>
          <div style={{ position: "relative" }}>
            <select
              value={filters.hospital}
              onChange={e => set("hospital", e.target.value)}
              style={selectStyle}
              onFocus={e => e.target.style.borderColor = "rgba(14,165,233,0.4)"}
              onBlur={e => e.target.style.borderColor = "rgba(148,163,184,0.1)"}
            >
              <option value="">All Hospitals</option>
              {HOSPITALS.map(h => (
                <option key={h} value={h}>{h}</option>
              ))}
            </select>
            <span style={{
              position: "absolute", right: 14, top: "50%",
              transform: "translateY(-50%)", color: "#475569",
              fontSize: 10, pointerEvents: "none",
            }}>▼</span>
          </div>
        </div>

        {/* Date */}
        <div style={{ marginBottom: 18, position: "relative" }} ref={calRef}>
          <label style={labelStyle}>Preferred Date</label>
          <button
            onClick={() => setShowCal(v => !v)}
            style={{
              ...selectStyle,
              display: "flex", alignItems: "center",
              justifyContent: "space-between", border: "1px solid rgba(148,163,184,0.1)",
              width: "100%", textAlign: "left" as const,
            }}
          >
            <span style={{ color: filters.date ? "#f1f5f9" : "#334155" }}>
              {filters.date ? `📅 ${formatDate(filters.date)}` : "📅 Select a date"}
            </span>
            <span style={{ color: "#475569", fontSize: 10 }}>{showCal ? "▲" : "▼"}</span>
          </button>
          {showCal && (
            <div style={{ position: "absolute", zIndex: 100, top: "calc(100% + 8px)", left: 0 }}>
              <Calendar
                selected={filters.date}
                onSelect={d => { set("date", d); setShowCal(false); }}
              />
            </div>
          )}
        </div>

        {/* Doctor name */}
        <div style={{ marginBottom: 28 }}>
          <label style={labelStyle}>Doctor Name</label>
          <input
            type="text"
            placeholder="e.g. Dr. Perera..."
            value={filters.doctorName}
            onChange={e => set("doctorName", e.target.value)}
            onKeyDown={e => e.key === "Enter" && handleSearch()}
            style={{
              ...selectStyle,
              cursor: "text",
            }}
            onFocus={e => e.target.style.borderColor = "rgba(14,165,233,0.4)"}
            onBlur={e => e.target.style.borderColor = "rgba(148,163,184,0.1)"}
          />
        </div>

        {/* Search button */}
        <button
          onClick={handleSearch}
          className="btn-glow"
          style={{ width: "100%", padding: "13px", fontSize: 15, borderRadius: 10 }}
        >
          Search Doctors →
        </button>
      </div>

      {/* Trust strip */}
      <div className="animate-fade-up-2" style={{
        display: "flex", gap: 28, marginTop: 32,
        flexWrap: "wrap", justifyContent: "center",
      }}>
        {[
          { icon: "🏥", text: "8 Hospitals" },
          { icon: "🩺", text: "50+ Specialists" },
          { icon: "💬", text: "WhatsApp Confirmed" },
          { icon: "⚡", text: "Instant Booking" },
        ].map(f => (
          <div key={f.text} style={{
            display: "flex", alignItems: "center", gap: 6,
            fontSize: 12, color: "#334155", fontWeight: 500,
          }}>
            <span style={{ fontSize: 14 }}>{f.icon}</span>
            {f.text}
          </div>
        ))}
      </div>

    </div>
  );
}